const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
```

### 2. Listens on all interfaces with no TLS (Low)
`app.listen(3000, ...)` binds to `0.0.0.0` by default. If this process runs directly on a host (not behind a reverse proxy terminating TLS), traffic is cleartext.

**Recommendation:** bind to `127.0.0.1` when a proxy (nginx/ALB) terminates TLS, or use `https.createServer` with a cert. Also read the port from `process.env.PORT`.
