const cors = require('cors');
const morgan = require('morgan');
const rateLimit = require('express-rate-limit');

const app = express();

app.disable('x-powered-by');
app.use(helmet());
app.use(cors({ origin: ['https://your-frontend.example'], methods: ['GET'] }));
app.use(morgan('combined'));
app.use(express.json({ limit: '100kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (_req, res) => res.json({ status: 'ok' }));

app.get('/users', /* requireAuth, */ (_req, res) => {
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

app.use((err, _req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'internal_error' });
});

const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || '127.0.0.1';
app.listen(PORT, HOST, () => console.log(`listening on ${HOST}:${PORT}`));

module.exports = app;
```

## Priority order

1. **Helmet + rate limiter + error handler** (one-liners, huge value).
2. **Auth on `/users`** and drop emails from the public response.
3. **Explicit CORS, bind address, body-size limit** before exposing publicly.
4. **Request logging** for audit.

