Anyone can list users and their email addresses — no auth check, no scoping (e.g., you can only see yourself). Even in a demo, this pattern is usually copied into production.

**Fix — require auth, and only expose fields the caller is entitled to:**
```js
const requireAuth = (req, res, next) => {
  const token = req.headers.authorization?.replace(/^Bearer\s+/i, '');
  if (!token) return res.status(401).json({ error: 'unauthorized' });
  try {
    req.user = verifyJwt(token); // HS256/RS256 with a rotated secret/key
    next();
  } catch {
    return res.status(401).json({ error: 'unauthorized' });
  }
};

