    const rows = req.user.role === 'admin'
      ? await db.listUsers()
      : [await db.getUser(req.user.sub)];
    // Minimize PII in the response.
    res.json(rows.map(({ id, name }) => ({ id, name })));
  } catch (err) { next(err); }
});
