  methods: ['GET'],
  credentials: false,
}));
```

---

### 5. `app.listen(3000)` binds to all interfaces — **Medium**
**OWASP:** A05 Security Misconfiguration

Node's default host is `0.0.0.0`, exposing the service on every NIC. In most deploys you want it behind a reverse proxy on loopback or a specific interface, and the port should come from env.

```js
const PORT = Number(process.env.PORT) || 3000;
const HOST = process.env.HOST || '127.0.0.1';
app.listen(PORT, HOST, () => {
  console.log(`Server running on ${HOST}:${PORT}`);
});
